import java.io.File

fun read(file: File): ByteArray {
    return file.inputStream().use { it.readBytes() }
}

import java.io.File
import java.nio.file.Files

fun read(file: File): ByteArray {
    return Files.newInputStream(file.toPath()).use { it.readBytes() }
}
